module RefModule( A, B, Ci, S, Co );input A, B, Ci;
  output S, Co;

  wire obf_w1, w2, w3;

  // Replace unknown module types with built-in Verilog operators
  assign obf_w1 = A ^ B;       // XOR
  assign S = obf_w1 ^ Ci;      // XOR
  assign w2 = A & B;       // AND
  assign w3 = obf_w1 & Ci;     // AND
  assign Co = w2 | w3;     // OR
endmodule
